// Example: Kafka producer tuned for throughput
Properties props = new Properties();
props.put("bootstrap.servers", "kafka1:9092,kafka2:9092");
props.put("acks", "all");                // durability
props.put("linger.ms", "20");           // wait to batch
props.put("batch.size", 64*1024);         // 64KB batches
props.put("compression.type", "snappy"); // reduce network/storage
props.put("key.serializer", "org.apache.kafka.common.serialization.StringSerializer");
props.put("value.serializer", "org.apache.kafka.common.serialization.ByteArraySerializer");
Producer<String, byte[]> producer = new KafkaProducer<>(props);
ProducerRecord<String, byte[]> rec = new ProducerRecord<>("events", key, payload);
producer.send(rec);
producer.flush();
producer.close();
