package main

// Very simplified conceptual sketch of leader AppendEntries invocation (non-production)
func leaderAppend(kvKey string, kvVal string) {
    // 1. append to local log
    entry := LogEntry{Term: currentTerm, Command: fmt.Sprintf("SET %s %s", kvKey, kvVal)}
    log.append(entry)

    // 2. send AppendEntries to followers concurrently
    for _, peer := range peers {
        go func(p Peer) {
            args := AppendEntriesArgs{Term: currentTerm, PrevLogIndex: prevIndex(p), PrevLogTerm: prevTerm(p), Entries: []LogEntry{entry}, LeaderCommit: commitIndex}
            reply := sendAppendEntries(p, args)
            if reply.Success {
                // record replication
                matchIndex[p] = args.PrevLogIndex + len(args.Entries)
            } else {
                // backoff/backtrack and retry
                nextIndex[p] = max(1, nextIndex[p]-1)
            }
        }(peer)
    }

    // 3. once majority have matchIndex >= newEntryIndex, advance commitIndex and apply
}
